diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 24a166906f1f..e632bc362a9e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1224,31 +1224,61 @@ static Instruction *combineAddSubWithShlAddSub(InstCombiner::BuilderTy &Builder,
   return nullptr;
 }

+/// Try to reduce signed division by power-of-2 to an arithmetic shift right.
 /// Try to reduce signed division by power-of-2 to an arithmetic shift right.
 static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // Division must be by power-of-2, but not the minimum signed value.
   Value *X;
   const APInt *DivC;
-  if (!match(Add.getOperand(0), m_SDiv(m_Value(X), m_Power2(DivC))) ||
-      DivC->isNegative())
+  Value *SextOp;
+  Value *SdivOp;
+  
+  // Check if operand 0 is sdiv and operand 1 is the sext pattern
+  if (match(Add.getOperand(0), m_SDiv(m_Value(X), m_Power2(DivC))) &&
+      !DivC->isNegative()) {
+    SdivOp = Add.getOperand(0);
+    SextOp = Add.getOperand(1);
+  }
+  // Check if operand 1 is sdiv and operand 0 is the sext pattern
+  else if (match(Add.getOperand(1), m_SDiv(m_Value(X), m_Power2(DivC))) &&
+           !DivC->isNegative()) {
+    SdivOp = Add.getOperand(1);
+    SextOp = Add.getOperand(0);
+  }
+  else
     return nullptr;

-  // Rounding is done by adding -1 if the dividend (X) is negative and has any
-  // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
-  // sext (icmp ugt (X & (DivC - 1)), SMIN)
-  const APInt *MaskC;
+  // Rounding is done by adding 1 if the dividend (X) is negative and has any
+  // low bits set. We match two patterns:
+  // 1. Canonical "ugt" pattern: sext (icmp ugt (X & Mask), SMin)
+  // 2. "eq" pattern (only for div by 2): sext (icmp eq (X & Mask), Mask)
+  const APInt *MaskC, *CmpC;
   ICmpInst::Predicate Pred;
-  if (!match(Add.getOperand(1),
+  if (!match(SextOp,
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_APInt(CmpC)))))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
-  if (*MaskC != (SMin | (*DivC - 1)))
+  APInt ExpectedMask = SMin | (*DivC - 1);
+  
+  // For the "ugt" pattern: (X & Mask) >u SMin, where Mask = SMin | (DivC - 1)
+  if (Pred == ICmpInst::ICMP_UGT) {
+    if (*MaskC != ExpectedMask || *CmpC != SMin)
+      return nullptr;
+  }
+  // For the "eq" pattern: only valid for divisor=2
+  // (X & Mask) == Mask where Mask = SMin | 1, equivalent to (X & Mask) >u SMin
+  else if (Pred == ICmpInst::ICMP_EQ) {
+    if (*DivC != 2)
+      return nullptr;
+    if (*MaskC != ExpectedMask || *CmpC != ExpectedMask)
+      return nullptr;
+  }
+  else
     return nullptr;

-  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
+  // (X / DivC) + sext ((X & Mask) pred Cmp) --> X >>s log2(DivC)
   return BinaryOperator::CreateAShr(
       X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
 }

